                    BIO_printf(bio_err,
                               "Unhandled error in the error queue during ECDH init.\n");
                    ERR_print_errors(bio_err);
                    rsa_count = 1;
                    break;
                }
                if (
                       !(pctx = EVP_PKEY_CTX_new_id(EVP_PKEY_EC, NULL)) ||
                       !EVP_PKEY_paramgen_init(pctx) ||
                       !EVP_PKEY_CTX_set_ec_paramgen_curve_nid(pctx,
